import { motion } from 'framer-motion';
import { ExternalLink } from 'lucide-react';

export const Footer = () => {
  return (
    <footer className="py-8 px-4 border-t border-border" data-testid="footer">
      <motion.div 
        className="max-w-5xl mx-auto text-center"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        <div className="mb-4">
          <span className="text-2xl font-bold blyx-brand">BlyxNova Studio</span>
        </div>
        <p className="text-sm text-muted-foreground mb-4">
          Creamos estrategias de contenido viral que transforman marcas
        </p>
        <div className="flex items-center justify-center gap-6 text-sm text-muted-foreground">
          <a href="#" className="hover:text-fuchsia-400 transition-colors flex items-center gap-1">
            Servicios <ExternalLink className="w-3 h-3" />
          </a>
          <a href="#" className="hover:text-fuchsia-400 transition-colors flex items-center gap-1">
            Portfolio <ExternalLink className="w-3 h-3" />
          </a>
          <a href="#" className="hover:text-fuchsia-400 transition-colors flex items-center gap-1">
            Contacto <ExternalLink className="w-3 h-3" />
          </a>
        </div>
        <p className="text-xs text-muted-foreground mt-6">
          © 2025 BlyxNova Studio. Este es un demo de portafolio.
        </p>
      </motion.div>
    </footer>
  );
};
